import styles from './index.module.css';
import { withKeepAlive, withRouter, history } from '../router';
import { memo, useRef } from 'react';

const TestBtns = memo((props) => {
  const inputRef = useRef()
  console.log('TestBtns', props);
  const go = (url, state = null) => {
    window.history.pushState(state, null, url);
  };
  const replace = (url) => {
    window.history.replaceState(null, null, url);
  }
  const back = () => {
    window.history.back();
  };
  const removeKeepAlive = () => {
    let val = inputRef.current.value || '';
    if (val) {
      const arr = val.split('/');
      props.removeKeepAlive(arr[0], arr[1]);
    }
  }
  const getAllAlive = () => {
    console.log(props.getAlive())
  };
  const push = (url) => {
    history.push(url)
  }
  return (
    <div className={styles['test-btns']}>
      <div className={styles['btn']} onClick={() => go('#/')}>push基本测试-跳转 /</div>
      <div className={styles['btn']} onClick={() => go('#/abc')}>push基本测试-跳转 /abc</div>
      <div className={styles['btn']} onClick={() => go('#/abc/1234', { data: 888 })}>push基本测试-跳转-query /abc/1234</div>
      <div className={styles['btn']} onClick={() => go('#/abc/de?pagekey=a')}>push基本测试-跳转push /abc/de?pagekey=a</div>
      <div className={styles['btn']} onClick={() => go('#/abc/de?pagekey=b')}>push基本测试-跳转push /abc/de?pagekey=b</div>
      <div className={styles['btn']} onClick={() => go('#/page/redirect')}>push重定向 /abc</div>
      <div className={styles['btn']} onClick={() => replace('#/abc/ssde?a=b')}>replace基本测试-跳转replace /abc/ssde</div>
      <div className={styles['btn']} onClick={() => go('#/abc/1234/detail?a=b')}>push基本测试-跳转replace /abc/1234/detail?a=b</div>
      <div className={styles['btn']} onClick={() => push('#/abc/1234/detail?a=b')}>history.push基本测试-跳转replace /abc/1234/detail?a=b</div>
      <div className={styles['btn']} onClick={() => back()}>基本测试-返回</div>
      <div className={styles['btn']}><span onClick={removeKeepAlive}>移除缓存页面</span><input ref={inputRef} /></div>
      <div className={styles['btn']} onClick={getAllAlive}>获取所有缓存页面</div>
    </div>
  );
})

export default withRouter(withKeepAlive(TestBtns));
